 * Handle a `delegate_task` tool_use emitted by the delegating agent.
 *
 * Runs the requested sub-agent on the delegated instructions, then feeds a
 * single tool_result back to the delegating agent so the conversation can
 * continue. The streamed tool_use id matches `tool_result.tool_use_id`.
 *
 * Handled cases:
 * - Circular delegation: stream-level error mentioning "circular"; no re-invoke.
 * - Unknown agent: stream-level error AND a tool_result with is_error true
 *   whose content mentions the requested agent_id.
 * - Sub-agent failure: only a tool_result with is_error true (no stream error).
 * - Success: a tool_result whose content is the sub-agent's accumulated text
 *   (or a placeholder when it produced none).
 */
async function* handleDelegation(
  agentId: string,
  response: ProviderResponse,
  request: ChatRequest,
  abortController: AbortController,
  debugMode: boolean,
  delegationChain: string[],
  turnDepth: number
): AsyncGenerator<StreamResponse> {
  const input = (response.toolInput ?? {}) as DelegateTaskInput;
  const subAgentId = (input.agent_id ?? "").trim();
  const instructions = input.instructions ?? "";
  const toolUseId = response.toolUseId ?? generateToolUseId();

  if (debugMode) {
    console.debug(
      `[Multi-Agent] Agent '${agentId}' delegating to '${subAgentId}' (tool_use ${toolUseId})`
    );
  }

  // Surface the delegation attempt with the id that the tool_result echoes.
  yield {
    type: "claude_json",
    data: {
      type: "tool_use",
      id: toolUseId,
      name: DELEGATE_TASK_TOOL,
      input: { agent_id: subAgentId, instructions },
      agentId,
      session_id: request.sessionId,
    },
  };

  // The chain of agents that are currently active on this delegation path.
  const chain = [...delegationChain, agentId];

  // Circular delegation: refuse before running anything.
  if (subAgentId && chain.includes(subAgentId)) {
    yield {
      type: "error",
      error: `Circular delegation detected: agent '${subAgentId}' is already active in the delegation chain [${[
        ...chain,
        subAgentId,
      ].join(" -> ")}]`,
    };
    return;
  }

  // Guard against runaway delegation loops.
  if (turnDepth >= MAX_DELEGATION_TURNS) {
    yield {
      type: "error",
      error: `Delegation limit reached (${MAX_DELEGATION_TURNS} turns); aborting further delegation`,
    };
    return;
  }

  let isError: boolean;
  let content: string;

  const subProvider = globalRegistry.getProviderForAgent(subAgentId);
  const subConfig = globalRegistry.getAgent(subAgentId);

  if (!subProvider || !subConfig) {
    // Unknown agent: stream-level error plus an is_error tool_result whose
    // content names the requested agent_id.
    yield {
      type: "error",
      error: `Agent '${subAgentId}' not found or provider not available`,
